/**
 * Returns workflow status transitions and field-level content edits for the report, interleaved by `createdAt` ascending so the UI can render a single chronological feed.
 * @summary Merged change history for a report
 */
export const GetReportTimelineParams = zod.object({
  id: zod.coerce.string().uuid(),
});

export const getReportTimelineResponseContentOneCategoryDefault = `report`;

export const GetReportTimelineResponseItem = zod
  .object({
    kind: zod.enum(["approval", "content"]),
    createdAt: zod.coerce.date(),
    approval: zod
      .union([
        zod.object({
          id: zod.string().uuid(),
          reportId: zod.string().uuid(),
          actor: zod.object({
            id: zod.string().uuid(),
            fullName: zod.string(),
            roles: zod
              .array(
                zod.enum([
                  "Employee",
                  "Manager Approver",
                  "Finance Approver",
                  "Accounting Admin",
                  "System Admin",
                ]),
              )
              .min(1),
          }),
          actorRoles: zod
            .array(
              zod.enum([
                "Employee",
                "Manager Approver",
                "Finance Approver",
                "Accounting Admin",
                "System Admin",
              ]),
            )
            .min(1),
          fromStatus: zod.enum([
            "Draft",
            "Submitted",
            "Manager Review",
            "Changes Requested",
            "Manager Approved",
            "Finance Review",
            "Finance Approved",
            "Posted to QuickBooks",
            "Ready for Payroll Reimbursement",
            "Paid Through Payroll",
            "Reconciled",
            "Rejected",
            "Voided",
            "Sync Error",
          ]),
          toStatus: zod.enum([
            "Draft",
            "Submitted",
            "Manager Review",
            "Changes Requested",
            "Manager Approved",
            "Finance Review",
            "Finance Approved",
            "Posted to QuickBooks",
            "Ready for Payroll Reimbursement",
            "Paid Through Payroll",
            "Reconciled",
            "Rejected",
            "Voided",
            "Sync Error",
          ]),
          comment: zod.string().nullish(),
          metadata: zod.string().nullish(),
          sequence: zod.number(),
          createdAt: zod.coerce.date(),
        }),
        zod.null(),
      ])
      .optional(),
    content: zod
      .union([
        zod
          .object({
            id: zod.string().uuid(),
            reportId: zod
              .string()
              .uuid()
              .nullable()
              .describe(
                "Null for QBO config\/tag\/mapping\/posting events that are not tied to a single report.",
              ),
            actor: zod.object({
              id: zod.string().uuid(),
              fullName: zod.string(),
              roles: zod
                .array(
                  zod.enum([
                    "Employee",
                    "Manager Approver",
                    "Finance Approver",
                    "Accounting Admin",
                    "System Admin",
                  ]),
                )
                .min(1),
            }),
            actorRoles: zod
              .array(
                zod.enum([
                  "Employee",
                  "Manager Approver",
                  "Finance Approver",
                  "Accounting Admin",
                  "System Admin",
                ]),
              )
              .min(1),
            category: zod
              .enum(["report", "qbo"])
              .default(getReportTimelineResponseContentOneCategoryDefault),
            entityType: zod.enum([
              "report",
              "line_item",
              "receipt",
              "qbo_config",
              "qbo_tag",
              "qbo_mapping",
              "qbo_posting",
            ]),
            entityId: zod.string().uuid(),
            action: zod.enum(["created", "updated", "deleted"]),
            fieldDiffs: zod.array(
              zod
                .object({
                  field: zod.string(),
                  before: zod.unknown(),
                  after: zod.unknown(),
                })
                .describe(
                  'One field-level change. `before` and `after` are the column\'s prior and new values, JSON-serialized. For \"created\" entries `before` is null; for \"deleted\" entries `after` is null.',
                ),
            ),
            createdAt: zod.coerce.date(),
          })
          .describe(
            "A field-level content edit on a report or one of its children (line item, receipt) — or, when `category=qbo`, a change to an org-wide QBO config, tag, GL mapping, or posting event. Approval\/status transitions live in `ApprovalAction`; merge them via `ChangeFeedItem`.",
          ),
        zod.null(),
      ])
      .optional(),
  })
  .describe(
    "Discriminated wrapper for the merged change-history feed used by `getReportTimeline` and `adminAuditLog`. `kind=approval` carries an `ApprovalAction`; `kind=content` carries an `AuditEntry`.",
  );
export const GetReportTimelineResponse = zod.array(
  GetReportTimelineResponseItem,
);

